    callback();
    return;
}

db.collection("sales_order")
    .where({ so_no: value })
    .get()
    .then(response => {
        const matchingSO = response.data || [];

        if (matchingSO.length === 0) {
            callback();
            return;
        }

        if (page_status === 'Edit') {
            const currentSoNo = this.getParamsVariables('sales_order_id');
            const isSameSoNo = matchingSO.some(so_no => so_no.id === currentSoNo);
            callback(isSameSoNo ? undefined : 'Sales order number already exists.');
        } else {
            callback('Sales order number already exists.');
        }
    })
    .catch(error => {
        console.error("Error checking sales order:", error);
        callback("Error validating sales order number.");
    });

