const checkAccIntegrationType = async () => {
  let organizationId = this.getVarGlobal("deptParentId");
  if (organizationId === "0") {
    organizationId = this.getVarSystem("deptIds").split(",")[0];
  }

  if (organizationId) {
    const resAI = await db
      .collection("accounting_integration")
      .where({ organization_id: organizationId })
      .get();

    if (resAI && resAI.data.length > 0) {
      const aiData = resAI.data[0];

      return aiData;
    } else {
      return null;
    }
  }
};

(async () => {
  const allListID = "custom_ezwb0qqp";
  this.showLoading("Post Goods Delivery...");
  let selectedRecords;

  selectedRecords = this.getComponent(allListID)?.$refs.crud.tableSelect;

  console.log("selectedRecords", selectedRecords);
  selectedRecords = selectedRecords.filter(
    (item) =>
      item.gd_status === "Completed" &&
      item.posted_status.dict_key !== "Posted",
  );

  if (selectedRecords.length === 0) {
    await this.$alert(
      "No selected records are available for posting. Please select records with status 'Completed' and not yet posted.",
      "No Records to Post",
      {
        confirmButtonText: "OK",
        dangerouslyUseHTMLString: true,
        type: "warning",
      },
    );
    this.getComponent(allListID)?.$refs.crud.clearSelection();
    this.hideLoading();
    return;
  }

  const aiData = await checkAccIntegrationType();
  switch (aiData.acc_integration_type) {
    case "SQL Accounting":
    case "AutoCount Accounting":
    case "AutoCount Accounting V2":
    case "No Accounting Integration":
      this.hideLoading();
      break;

    case "SQL Accounting V2":
      await this.runWorkflow(
        "2013511169625042946",
        {
          agent_id: aiData.agent_id,
          task_type: "post_gd",
          payload: selectedRecords.map((item) => item.id),
          priority: "0",
        },
        async (res) => {
          console.log("成功结果：", res);
          this.hideLoading();
        },
        (err) => {
          console.log("失败结果：", err);
          this.getComponent(allListID)?.$refs.crud.clearSelection();
          this.hideLoading();
        },
      );
      break;
  }

  this.getComponent(allListID)?.$refs.crud.clearSelection();
  this.refresh();
})();

